toolRequests.arguments:
{"command":"$srcOld=(git rev-parse a61c299^).Trim(); $srcNew=(git rev-parse 73b0907^).Trim();
$oldDirs = git ls-tree -d --name-only "${srcOld}:.planning/phases";
$newDirs = git ls-tree -d --name-only "${srcNew}:.planning/phases";
$restored=@(); $skipped=@(); $missing=@();
for($i=1;$i -le 32;$i++){
  $p = '{0:D2}' -f $i
  $existing = Get-ChildItem .planning/phases -Directory -ErrorAction SilentlyContinue | Where-Object { $_.Name -like "$p-*" } | Select-Object -First 1
  if($existing){ $skipped += "$p (kept current: $($existing.Name))"; continue }

  $candNew = $newDirs | Where-Object { $_ -like "$p-*" } | Select-Object -First 1
  $candOld = $oldDirs | Where-Object { $_ -like "$p-*" } | Select-Object -First 1
  $chosen = $candNew
  $src = $srcNew
  if(-not $chosen){ $chosen = $candOld; $src = $srcOld }

  if($chosen){
    git checkout $src -- ".planning/phases/$chosen" | Out-Null
    $restored += "$p -> $chosen"
  } else {
    $missing += $p
  }
}
"RESTORED:"; $restored;
"SKIPPED:"; $skipped;
"NO_SOURCE_FOUND:"; $missing;
","explanation":"Restore missing phase directories 01-32 from git history without overwriting existing ones","goal":"Recover lost phase files and keep current versions when conflicts could occur","mode":"sync"}

